        }
    });
    localStorage.setItem(ORDER_KEY, JSON.stringify(orders));
    if (isOnline()) await batch.commit();
    window.dispatchEvent(new Event('storage_' + ORDER_KEY));
  },

  /* FIX: Added missing updatePaymentVerification method */
  updatePaymentVerification: async (id: string, verified: boolean, _meta?: any) => {
    const orders = ensureOrdersLoaded();
    const idx = orders.findIndex(o => o.id === id);
    if (idx >= 0) {
