    try {
        const local = localStorage.getItem(NOTIF_KEY);
        if (local) {
            const list = JSON.parse(local) as Notification[];
            list.forEach(n => n.isRead = true);
            localStorage.setItem(NOTIF_KEY, JSON.stringify(list));
        }
    } catch {}
    if (isOnline()) {
        const q = query(collection(db, "notifications"), where("isRead", "==", false), limit(50));
        const snap = await getDocs(q);
        const batch = writeBatch(db);
        snap.forEach(d => batch.update(d.ref, { isRead: true }));
        await batch.commit();
    }
    window.dispatchEvent(new CustomEvent('local_notif_read_all'));
  },

  /* FIX: Added missing clearAllNotifications method */
  clearAllNotifications: async () => {
    localStorage.removeItem(NOTIF_KEY);
    if (isOnline()) {
        const q = query(collection(db, "notifications"), limit(50));
        const snap = await getDocs(q);
        const batch = writeBatch(db);
        snap.forEach(d => batch.delete(d.ref));
        await batch.commit();
    }
    window.dispatchEvent(new CustomEvent('local_notif_clear_all'));
  },

  /* FIX: Added missing findMatchingCustomer method */
  findMatchingCustomer: (phone: string, address: string) => {
    const list = ensureCustomersLoaded();
    const p = normalizePhone(phone);
    if (p.length > 8) return list.find(c => normalizePhone(c.phone) === p);
    return list.find(c => normalizeString(c.address) === normalizeString(address));
  },

  /* FIX: Added missing generatePerformanceData method */
  generatePerformanceData: async (count: number) => {
    const start = Date.now();
    const list = ensureCustomersLoaded();
    for(let i=0; i<count; i++) {
        list.push({
            id: uuidv4(),
            name: `Stress Test ${i}`,
            phone: '0900000000',
            address: 'Stress Test Address',
            lastOrderDate: Date.now(),
            totalOrders: 0,
            updatedAt: Date.now()
        });
    }
    localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list.slice(0, 15000)));
    return { count, duration: Date.now() - start };
  },

  /* FIX: Added missing markAllCustomersAsOld method */
  markAllCustomersAsOld: async () => {
    const list = ensureCustomersLoaded();
    list.forEach(c => c.isLegacy = true);
    localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
