  /* FIX: Added missing getProductOrderHistory method */
  getProductOrderHistory: (productId: string) => {
    const orders = ensureOrdersLoaded();
    const history: {order: Order, quantity: number}[] = [];
    orders.forEach(o => {
        o.items.forEach(item => {
            if (item.productId === productId) {
                history.push({ order: o, quantity: item.quantity });
            }
        });
    });
    return history;
  }
};

