      const list = getLocal<Customer[]>(CUSTOMER_KEY, []);
      const p = normalizePhone(phone);
      if (p.length > 8) return list.find(c => normalizePhone(c.phone) === p);
      return list.find(c => normalizeString(c.address) === normalizeString(address));
  },

  getProductOrderHistory: (id: string) => {
      const orders = getLocal<Order[]>(ORDER_KEY, []);
      const history: any[] = [];
      orders.forEach(o => {
          o.items.forEach(it => { if (it.productId === id) history.push({ order: o, quantity: it.quantity }); });
      });
      return history;
  },

  fetchLongTermStats: async () => {
      if (isOnline()) { const s = await getDocs(query(collection(db, "orders"), limit(2000))); return s.docs.map(d => d.data() as Order); }
      return getLocal<Order[]>(ORDER_KEY, []);
  },

  incrementReminderCount: async (ids: string[]) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      ids.forEach(id => { const o = list.find(x => x.id === id); if (o) o.reminderCount = (o.reminderCount || 0) + 1; });
      setLocal(ORDER_KEY, list);
  },

  generatePerformanceData: async (count: number) => ({ count, duration: 0 }),
  markAllCustomersAsOld: async () => 0
};

import React, { useEffect, useState, useMemo, useDeferredValue, useCallback } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import { OrderCard } from './OrderCard';
import ConfirmModal from './ConfirmModal';
import RoutePlannerModal from './RoutePlannerModal';

const TrackingDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState<OrderStatus[]>([]);
  const [filterBatch, setFilterBatch] = useState<string>('ALL');

  const [isCompactMode, setIsCompactMode] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [showRoutePlanner, setShowRoutePlanner] = useState(false);

  const deferredSearch = useDeferredValue(searchTerm);

  useEffect(() => {
    const unsub = storageService.subscribeOrders(setOrders);
    return () => { if (unsub) unsub(); };
  }, []);

  const batches = useMemo(() => {
      const set = new Set<string>();
      orders.forEach(o => { if (o.batchId) set.add(o.batchId); });
      return Array.from(set).sort().reverse();
  }, [orders]);

  const filteredOrders = useMemo(() => {
      return orders.filter(o => {
          const matchStatus = filterStatus.length === 0 || filterStatus.includes(o.status);
          const matchBatch = filterBatch === 'ALL' || o.batchId === filterBatch;
          if (!matchStatus || !matchBatch) return false;

          if (!deferredSearch) return true;
          const term = normalizeString(deferredSearch);
          return normalizeString(o.customerName).includes(term) || 
                 normalizePhone(o.customerPhone).includes(term) ||
                 normalizeString(o.address).includes(term);
      });
  }, [orders, filterStatus, filterBatch, deferredSearch]);

  const handleDelete = (id: string) => { setDeleteId(id); setShowDeleteConfirm(true); };
  const confirmDelete = async () => { 
      if (deleteId) { 
          await storageService.deleteOrder(deleteId); 
          toast.success("Đã xóa đơn hàng"); 
          setShowDeleteConfirm(false); 
      } 
  };

  const toggleStatusFilter = (s: OrderStatus) => {
      setFilterStatus(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s]);
  };

  return (
    <div className="pb-32 animate-fade-in">
      <div className="sticky top-16 z-30 bg-white shadow-sm border-b border-gray-100 p-3 space-y-3">
          <div className="flex gap-2">
              <div className="relative flex-grow">
                  <i className="fas fa-search absolute left-3 top-3 text-gray-400"></i>
                  <input 
                    value={searchTerm} 
                    onChange={e => setSearchTerm(e.target.value)}
                    placeholder="Tìm tên, SĐT, địa chỉ..." 
                    className="w-full pl-9 pr-4 py-2.5 bg-gray-100 rounded-xl outline-none focus:bg-white border-2 border-transparent focus:border-eco-500 font-bold transition-all" 
                  />
              </div>
              <button onClick={() => setIsCompactMode(!isCompactMode)} className={`w-11 h-11 rounded-xl flex items-center justify-center border-2 transition-all ${isCompactMode ? 'bg-eco-600 border-eco-600 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                  <i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th-large'}`}></i>
              </button>
          </div>

          <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
              <select value={filterBatch} onChange={e => setFilterBatch(e.target.value)} className="px-3 py-1.5 bg-gray-100 rounded-lg text-xs font-black uppercase outline-none shrink-0 border-2 border-transparent focus:border-gray-300">
                  <option value="ALL">Tất cả lô hàng</option>
                  {batches.map(b => <option key={b} value={b}>{b}</option>)}
              </select>
              {[OrderStatus.PENDING, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].map(s => (
                  <button 
                    key={s} 
                    onClick={() => toggleStatusFilter(s)}
                    className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all shrink-0 ${filterStatus.includes(s) ? 'bg-eco-600 text-white shadow-md' : 'bg-gray-100 text-gray-500'}`}
                  >
                      {s === OrderStatus.PENDING ? 'Chờ' : s === OrderStatus.IN_TRANSIT ? 'Giao' : 'Xong'}
                  </button>
              ))}
              <button onClick={() => setShowRoutePlanner(true)} className="ml-auto px-4 py-1.5 bg-black text-white rounded-lg text-[10px] font-black uppercase shrink-0"><i className="fas fa-route mr-1"></i> Lộ trình</button>
          </div>
      </div>

      <div className={`mt-4 ${isCompactMode ? 'bg-white rounded-2xl overflow-hidden shadow-sm divide-y' : 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4'}`}>
          {filteredOrders.length === 0 ? (
              <div className="col-span-full py-20 text-center text-gray-300">
                  <i className="fas fa-box-open text-6xl mb-4 opacity-20"></i>
                  <p className="font-bold uppercase tracking-widest text-xs">Không có đơn hàng nào</p>
              </div>
          ) : (
              filteredOrders.map((o, idx) => (
                  <OrderCard 
                    key={o.id} 
                    order={o} 
                    index={idx}
                    isCompactMode={isCompactMode}
                    onDelete={handleDelete}
                    onEdit={() => {}}
                    onUpdate={() => {}}
                  />
              ))
          )}
      </div>

      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa đơn hàng?" message="Hành động này sẽ hoàn lại hàng vào kho và không thể khôi phục." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} isDanger={true} />
      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders.filter(o => o.status !== OrderStatus.DELIVERED)} onApplySort={() => {}} />
    </div>
  );
};

export default TrackingDashboard;

import React from 'react';
import { Order, OrderStatus, PaymentMethod } from '../types';
import { storageService } from '../services/storageService';
import toast from 'react-hot-toast';

interface Props {
  order: Order;
  onUpdate: (order: Order) => void;
  onDelete: (id: string) => void;
  onEdit: (order: Order) => void;
  index?: number;
  isCompactMode?: boolean;
}

const statusStyle: Record<OrderStatus, string> = {
  [OrderStatus.PENDING]: 'bg-yellow-100 text-yellow-700',
  [OrderStatus.PICKED_UP]: 'bg-blue-100 text-blue-700',
  [OrderStatus.IN_TRANSIT]: 'bg-purple-100 text-purple-700',
  [OrderStatus.DELIVERED]: 'bg-green-100 text-green-700',
  [OrderStatus.CANCELLED]: 'bg-red-100 text-red-700',
};

const statusLabel: Record<OrderStatus, string> = {
  [OrderStatus.PENDING]: 'Chờ xử lý',
  [OrderStatus.PICKED_UP]: 'Đã lấy',
  [OrderStatus.IN_TRANSIT]: 'Đang giao',
  [OrderStatus.DELIVERED]: 'Đã giao',
  [OrderStatus.CANCELLED]: 'Đã hủy',
};

export const OrderCard: React.FC<Props> = ({ order, onDelete, isCompactMode, index }) => {

  const handleStatusNext = async (e: React.MouseEvent) => {
      e.stopPropagation();
      let next: OrderStatus = order.status;
      if (order.status === OrderStatus.PENDING) next = OrderStatus.PICKED_UP;
      else if (order.status === OrderStatus.PICKED_UP) next = OrderStatus.IN_TRANSIT;
      else if (order.status === OrderStatus.IN_TRANSIT) next = OrderStatus.DELIVERED;

      await storageService.updateStatus(order.id, next);
      toast.success(`Đã chuyển sang: ${statusLabel[next]}`);
  };

  const handleTogglePayment = async (e: React.MouseEvent) => {
      e.stopPropagation();
      if (order.paymentMethod !== PaymentMethod.TRANSFER) return;
      await storageService.updatePaymentVerification(order.id, !order.paymentVerified);
      toast.success(order.paymentVerified ? "Đã gỡ xác nhận" : "Đã khớp tiền!");
  };

  if (isCompactMode) {
      return (
          <div className="p-3 flex items-center gap-3 bg-white hover:bg-gray-50 transition-colors border-b border-gray-50">
              <div className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center text-[10px] font-black text-gray-400 shrink-0">{(index || 0) + 1}</div>
              <div className="flex-grow min-w-0">
                  <div className="flex justify-between items-baseline mb-0.5">
                      <h4 className="font-black text-gray-800 text-sm truncate uppercase">{order.customerName}</h4>
                      <span className="font-black text-gray-900 text-sm">{new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ</span>
                  </div>
                  <div className="flex items-center gap-2">
                      <span className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase ${statusStyle[order.status]}`}>{statusLabel[order.status]}</span>
                      <p className="text-[10px] text-gray-400 truncate">{order.address}</p>
                  </div>
              </div>
              <button onClick={handleStatusNext} className="w-9 h-9 rounded-xl bg-gray-900 text-white flex items-center justify-center shrink-0 shadow-md active:scale-90 transition-all"><i className="fas fa-chevron-right text-xs"></i></button>
          </div>
      );
  }

  return (
    <div className="bg-white rounded-3xl border-2 border-gray-100 shadow-sm overflow-hidden hover:shadow-xl hover:border-gray-200 transition-all flex flex-col h-full group">
        <div className="p-4 flex-grow">
            <div className="flex justify-between items-start mb-3">
                <div className="min-w-0">
                    <h3 className="font-black text-gray-800 uppercase text-base truncate tracking-tighter leading-none mb-1">{order.customerName}</h3>
                    <div className="flex items-center gap-2">
                        <span className="text-[10px] font-mono font-bold text-gray-400">{order.customerPhone}</span>
                        <span className={`text-[9px] font-black px-2 py-0.5 rounded-full uppercase ${statusStyle[order.status]}`}>{statusLabel[order.status]}</span>
                    </div>
                </div>
                <button onClick={(e) => { e.stopPropagation(); onDelete(order.id); }} className="w-8 h-8 rounded-full bg-red-50 text-red-300 hover:text-red-500 flex items-center justify-center transition-colors opacity-0 group-hover:opacity-100"><i className="fas fa-trash-alt text-xs"></i></button>
            </div>

            <div className="bg-gray-50 rounded-2xl p-3 border border-gray-100 mb-3 space-y-1">
                {order.items.map((it, i) => (
                    <div key={i} className="flex justify-between text-xs font-bold text-gray-700">
                        <span className="truncate mr-2 uppercase">{it.name}</span>
                        <span className="text-gray-400 shrink-0">x{it.quantity}</span>
                    </div>
                ))}
            </div>

            <div className="flex items-start gap-2 text-[10px] text-gray-500 font-medium">
                <i className="fas fa-map-marker-alt text-red-400 mt-0.5"></i>
                <span className="line-clamp-2">{order.address}</span>
            </div>
        </div>

        <div className="px-4 py-3 bg-gray-50 border-t border-gray-100 mt-auto flex justify-between items-center">
            <div>
                <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Tổng thu</div>
                <div className="text-lg font-black text-gray-900 tracking-tighter">{new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ</div>
            </div>

            <div className="flex gap-2">
                {order.paymentMethod === PaymentMethod.TRANSFER && (
                    <button onClick={handleTogglePayment} className={`px-3 py-2 rounded-xl text-[10px] font-black uppercase border-2 transition-all ${order.paymentVerified ? 'bg-green-50 border-green-500 text-green-700' : 'bg-blue-50 border-blue-200 text-blue-600'}`}>
                        {order.paymentVerified ? 'Đã nhận' : 'Chờ CK'}
                    </button>
                )}
                <button onClick={handleStatusNext} className="h-10 px-4 bg-black text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-gray-200 active:scale-95 transition-all">
                    {order.status === OrderStatus.DELIVERED ? 'Xong ✅' : 'Tiếp theo'}
                </button>
            </div>
        </div>
    </div>
  );
};

import { Order, OrderStatus, Product, Customer, BankConfig, Notification, ShopConfig, ImportRecord, OrderItem, PaymentMethod } from '../types';
import { db } from '../firebaseConfig';
import { v4 as uuidv4 } from 'uuid';
import { 
  collection, 
  setDoc, 
  doc, 
  updateDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs, 
  writeBatch, 
  deleteField, 
  limit, 
  getDoc, 
  where, 
  increment,
  runTransaction 
} from "firebase/firestore";

const ORDER_KEY = 'ecogo_orders_v3'; 
const PRODUCT_KEY = 'ecogo_products_v1';
const CUSTOMER_KEY = 'ecogo_customers_v1';
const USER_KEY = 'ecogo_current_user';
const BANK_KEY = 'ecogo_bank_config';
const SHOP_KEY = 'ecogo_shop_config';
const NOTIF_KEY = 'ecogo_notifications_v1';
const TAGS_KEY = 'ecogo_quick_tags';
const LOGO_KEY = 'ecogo_company_logo';

const isOnline = () => !!db;

const getLocal = <T>(key: string, fallback: T): T => {
    try {
        const val = localStorage.getItem(key);
        return val ? JSON.parse(val) : fallback;
    } catch { return fallback; }
};

const setLocal = (key: string, val: any) => {
    localStorage.setItem(key, JSON.stringify(val));
    window.dispatchEvent(new Event('storage_' + key));
};

export const normalizeString = (str: string): string => {
    if (!str) return "";
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
};

export const normalizePhone = (phone: string) => {
    if (!phone) return '';
    let p = phone.replace(/[^0-9]/g, '');
    if (p.startsWith('84')) p = '0' + p.slice(2);
    if (p.startsWith('+84')) p = '0' + p.slice(3);
    return p;
};

export const generateProductSku = (name: string): string => {
    if (!name) return uuidv4();
    return name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "_");
};

const sanitize = (obj: any) => JSON.parse(JSON.stringify(obj));

export const storageService = {
  login: (username: string) => localStorage.setItem(USER_KEY, username),
  logout: () => localStorage.removeItem(USER_KEY),
  getCurrentUser: () => localStorage.getItem(USER_KEY),

  getLogo: () => localStorage.getItem(LOGO_KEY),
  saveLogo: (base64: string) => { localStorage.setItem(LOGO_KEY, base64); window.dispatchEvent(new Event('logo_updated')); },
  removeLogo: () => { localStorage.removeItem(LOGO_KEY); window.dispatchEvent(new Event('logo_updated')); },

  getQuickTags: () => getLocal(TAGS_KEY, ["Dễ vỡ", "Gọi trước", "Cổng sau"]),
  saveQuickTags: async (tags: string[]) => { setLocal(TAGS_KEY, tags); if (isOnline()) await setDoc(doc(db, "settings", "quickTags"), { tags }); },
  fetchQuickTagsFromCloud: async () => { if (isOnline()) { const s = await getDoc(doc(db, "settings", "quickTags")); if (s.exists()) return s.data().tags; } return storageService.getQuickTags(); },

  saveShopConfig: async (config: ShopConfig) => { setLocal(SHOP_KEY, config); if (isOnline()) await setDoc(doc(db, "settings", "shopConfig"), sanitize(config)); },
  getShopConfig: async () => getLocal(SHOP_KEY, null),

  saveBankConfig: async (config: BankConfig) => { setLocal(BANK_KEY, config); if (isOnline()) await setDoc(doc(db, "settings", "bankConfig"), sanitize(config)); },
  getBankConfig: async () => getLocal(BANK_KEY, null),

  getAllProducts: () => getLocal<Product[]>(PRODUCT_KEY, []),
  subscribeProducts: (callback: (prods: Product[]) => void) => {
    callback(storageService.getAllProducts());
    if (isOnline()) return onSnapshot(query(collection(db, "products"), orderBy("updatedAt", "desc"), limit(500)), (snap) => {
        const list = snap.docs.map(d => d.data() as Product);
        if (list.length > 0) { setLocal(PRODUCT_KEY, list); callback(list); }
    });
  },

  saveProduct: async (p: Product) => {
      const list = storageService.getAllProducts();
      const idx = list.findIndex(x => x.id === p.id);
      const pSave = { ...p, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = pSave; else list.unshift(pSave);
      setLocal(PRODUCT_KEY, list);
      if (isOnline()) await setDoc(doc(db, "products", p.id), sanitize(pSave));
  },

  adjustStockAtomic: async (id: string, delta: number, info?: any) => {
      const list = storageService.getAllProducts();
      const p = list.find(x => x.id === id);
      if (p) {
          p.stockQuantity = (p.stockQuantity || 0) + delta;
          if (delta > 0) {
              p.totalImported = (p.totalImported || 0) + delta;
              if (!p.importHistory) p.importHistory = [];
              p.importHistory.push({ id: uuidv4(), date: Date.now(), quantity: delta, price: info?.price || 0 });
          }
          p.updatedAt = Date.now();
          setLocal(PRODUCT_KEY, list);
      }
      if (isOnline()) await runTransaction(db, async (tx) => {
          const ref = doc(db, "products", id);
          const snap = await tx.get(ref);
          if (snap.exists()) {
              const data = snap.data() as Product;
              const updates: any = { stockQuantity: increment(delta), updatedAt: Date.now() };
              if (delta > 0) {
                  updates.totalImported = increment(delta);
                  const h = [...(data.importHistory || []), { id: uuidv4(), date: Date.now(), quantity: delta, price: info?.price || 0 }];
                  updates.importHistory = h;
              }
              tx.update(ref, updates);
          }
      });
  },

  deleteProduct: async (id: string) => {
      const list = storageService.getAllProducts().filter(x => x.id !== id);
      setLocal(PRODUCT_KEY, list);
      if (isOnline()) await deleteDoc(doc(db, "products", id));
  },

  subscribeOrders: (callback: (orders: Order[]) => void) => {
    callback(getLocal<Order[]>(ORDER_KEY, []));
    if (isOnline()) return onSnapshot(query(collection(db, "orders"), orderBy("createdAt", "desc"), limit(400)), (snap) => {
        const list = snap.docs.map(d => d.data() as Order);
        setLocal(ORDER_KEY, list);
        callback(list);
    });
  },

  saveOrder: async (o: Order) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      list.unshift(o);
      setLocal(ORDER_KEY, list);

      const prods = storageService.getAllProducts();
      o.items.forEach(item => {
          const p = prods.find(x => x.id === item.productId);
          if (p) p.stockQuantity -= item.quantity;
      });
      setLocal(PRODUCT_KEY, prods);

      if (isOnline()) await runTransaction(db, async (tx) => {
          for (const item of o.items) {
              if (item.productId) tx.update(doc(db, "products", item.productId), { stockQuantity: increment(-item.quantity), updatedAt: Date.now() });
          }
          tx.set(doc(db, "orders", o.id), sanitize(o));
      });
  },

  deleteOrder: async (id: string) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const o = list.find(x => x.id === id);
      if (!o) return;

      setLocal(ORDER_KEY, list.filter(x => x.id !== id));
      const prods = storageService.getAllProducts();
      o.items.forEach(item => {
          const p = prods.find(x => x.id === item.productId);
          if (p) p.stockQuantity += item.quantity;
      });
      setLocal(PRODUCT_KEY, prods);

      if (isOnline()) await runTransaction(db, async (tx) => {
          const ref = doc(db, "orders", id);
          const snap = await tx.get(ref);
          if (snap.exists()) {
              const data = snap.data() as Order;
              for (const it of data.items) {
                  if (it.productId) tx.update(doc(db, "products", it.productId), { stockQuantity: increment(it.quantity), updatedAt: Date.now() });
              }
              tx.delete(ref);
          }
      });
  },

  deleteOrdersBatch: async (ids: string[]) => { for (const id of ids) await storageService.deleteOrder(id); },

  updateStatus: async (id: string, status: OrderStatus, proof?: string, meta?: any) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const idx = list.findIndex(x => x.id === id);
      if (idx >= 0) {
          list[idx].status = status;
          list[idx].updatedAt = Date.now();
          if (proof) list[idx].deliveryProof = proof;
          setLocal(ORDER_KEY, list);
          if (isOnline()) await updateDoc(doc(db, "orders", id), { status, updatedAt: Date.now(), deliveryProof: proof || deleteField() });
      }
  },

  updateOrderDetails: async (o: Order) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const idx = list.findIndex(x => x.id === o.id);
      if (idx >= 0) {
          list[idx] = { ...o, updatedAt: Date.now() };
          setLocal(ORDER_KEY, list);
          if (isOnline()) await setDoc(doc(db, "orders", o.id), sanitize(list[idx]));
      }
  },

  updatePaymentVerification: async (id: string, verified: boolean) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const idx = list.findIndex(x => x.id === id);
      if (idx >= 0) {
          list[idx].paymentVerified = verified;
          list[idx].updatedAt = Date.now();
          setLocal(ORDER_KEY, list);
          if (isOnline()) await updateDoc(doc(db, "orders", id), { paymentVerified: verified, updatedAt: Date.now() });
      }
  },

  moveOrdersBatch: async (ids: string[], target: string) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const batch = isOnline() ? writeBatch(db) : null;
      ids.forEach(id => {
          const o = list.find(x => x.id === id);
          if (o) {
              o.batchId = target;
              o.updatedAt = Date.now();
              if (batch) batch.update(doc(db, "orders", id), { batchId: target, updatedAt: o.updatedAt });
          }
      });
      setLocal(ORDER_KEY, list);
      if (batch) await batch.commit();
  },

  subscribeCustomers: (callback: (c: Customer[]) => void) => {
      callback(getLocal<Customer[]>(CUSTOMER_KEY, []));
      if (isOnline()) return onSnapshot(query(collection(db, "customers"), orderBy("updatedAt", "desc"), limit(1000)), (snap) => {
          const list = snap.docs.map(d => d.data() as Customer);
          setLocal(CUSTOMER_KEY, list);
          callback(list);
      });
  },

  upsertCustomer: async (c: Customer) => {
      const list = getLocal<Customer[]>(CUSTOMER_KEY, []);
      const idx = list.findIndex(x => x.id === c.id);
      const cSave = { ...c, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = cSave; else list.unshift(cSave);
      setLocal(CUSTOMER_KEY, list);
      if (isOnline()) await setDoc(doc(db, "customers", c.id), sanitize(cSave));
  },

  deleteCustomer: async (id: string) => {
      setLocal(CUSTOMER_KEY, getLocal<Customer[]>(CUSTOMER_KEY, []).filter(x => x.id !== id));
      if (isOnline()) await deleteDoc(doc(db, "customers", id));
  },

  subscribeNotifications: (callback: (n: Notification[]) => void) => {
      callback(getLocal<Notification[]>(NOTIF_KEY, []));
      if (isOnline()) return onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc"), limit(50)), (snap) => {
          const list = snap.docs.map(d => d.data() as Notification);
          setLocal(NOTIF_KEY, list);
          callback(list);
      });
  },

  markNotificationRead: async (id: string) => {
      if (isOnline()) await updateDoc(doc(db, "notifications", id), { isRead: true });
  },

  markAllNotificationsRead: async () => {
      const list = getLocal<Notification[]>(NOTIF_KEY, []);
      list.forEach(n => n.isRead = true);
      setLocal(NOTIF_KEY, list);
  },

  clearAllNotifications: async () => localStorage.removeItem(NOTIF_KEY),

  findMatchingCustomer: (phone: string, address: string) => {
      const list = getLocal<Customer[]>(CUSTOMER_KEY, []);
      const p = normalizePhone(phone);
      if (p.length > 8) return list.find(c => normalizePhone(c.phone) === p);
      return list.find(c => normalizeString(c.address) === normalizeString(address));
  },

  getProductOrderHistory: (id: string) => {
      const orders = getLocal<Order[]>(ORDER_KEY, []);
      const history: any[] = [];
      orders.forEach(o => {
          o.items.forEach(it => { if (it.productId === id) history.push({ order: o, quantity: it.quantity }); });
      });
      return history;
  },

  fetchLongTermStats: async () => {
      if (isOnline()) { const s = await getDocs(query(collection(db, "orders"), limit(2000))); return s.docs.map(d => d.data() as Order); }
      return getLocal<Order[]>(ORDER_KEY, []);
  },

  incrementReminderCount: async (ids: string[]) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      ids.forEach(id => { const o = list.find(x => x.id === id); if (o) o.reminderCount = (o.reminderCount || 0) + 1; });
      setLocal(ORDER_KEY, list);
  },

  generatePerformanceData: async (count: number) => ({ count, duration: 0 }),
  markAllCustomersAsOld: async () => 0
};

import React, { useEffect, useState, useMemo, useDeferredValue } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import { OrderCard } from './OrderCard';
import ConfirmModal from './ConfirmModal';
import RoutePlannerModal from './RoutePlannerModal';

const TrackingDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState<OrderStatus[]>([]);
  const [filterBatch, setFilterBatch] = useState<string>('ALL');

  const [isCompactMode, setIsCompactMode] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [showRoutePlanner, setShowRoutePlanner] = useState(false);

  const deferredSearch = useDeferredValue(searchTerm);

  useEffect(() => {
    const unsub = storageService.subscribeOrders(setOrders);
    return () => { if (unsub) unsub(); };
  }, []);

  const batches = useMemo(() => {
      const set = new Set<string>();
      orders.forEach(o => { if (o.batchId) set.add(o.batchId); });
      return Array.from(set).sort().reverse();
  }, [orders]);

  const filteredOrders = useMemo(() => {
      return orders.filter(o => {
          const matchStatus = filterStatus.length === 0 || filterStatus.includes(o.status);
          const matchBatch = filterBatch === 'ALL' || o.batchId === filterBatch;
          if (!matchStatus || !matchBatch) return false;

          if (!deferredSearch) return true;
          const term = normalizeString(deferredSearch);
          return normalizeString(o.customerName).includes(term) || 
                 normalizePhone(o.customerPhone).includes(term) ||
                 normalizeString(o.address).includes(term);
      });
  }, [orders, filterStatus, filterBatch, deferredSearch]);

  const handleDelete = (id: string) => { setDeleteId(id); setShowDeleteConfirm(true); };
  const confirmDelete = async () => { 
      if (deleteId) { 
          await storageService.deleteOrder(deleteId); 
          toast.success("Đã xóa đơn hàng"); 
          setShowDeleteConfirm(false); 
      } 
  };

  const toggleStatusFilter = (s: OrderStatus) => {
      setFilterStatus(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s]);
  };

  return (
    <div className="pb-32 animate-fade-in">
      <div className="sticky top-16 z-30 bg-white shadow-sm border-b border-gray-100 p-3 space-y-3">
          <div className="flex gap-2">
              <div className="relative flex-grow">
                  <i className="fas fa-search absolute left-3 top-3 text-gray-400"></i>
                  <input 
                    value={searchTerm} 
                    onChange={e => setSearchTerm(e.target.value)}
                    placeholder="Tìm tên, SĐT, địa chỉ..." 
                    className="w-full pl-9 pr-4 py-2.5 bg-gray-100 rounded-xl outline-none focus:bg-white border-2 border-transparent focus:border-eco-500 font-bold transition-all" 
                  />
              </div>
              <button onClick={() => setIsCompactMode(!isCompactMode)} className={`w-11 h-11 rounded-xl flex items-center justify-center border-2 transition-all ${isCompactMode ? 'bg-eco-600 border-eco-600 text-white' : 'bg-white border-gray-200 text-gray-400'}`}>
                  <i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th-large'}`}></i>
              </button>
          </div>

          <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
              <select value={filterBatch} onChange={e => setFilterBatch(e.target.value)} className="px-3 py-1.5 bg-gray-100 rounded-lg text-xs font-black uppercase outline-none shrink-0 border-2 border-transparent focus:border-gray-300">
                  <option value="ALL">Tất cả lô hàng</option>
                  {batches.map(b => <option key={b} value={b}>{b}</option>)}
              </select>
              {[OrderStatus.PENDING, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].map(s => (
                  <button 
                    key={s} 
                    onClick={() => toggleStatusFilter(s)}
                    className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all shrink-0 ${filterStatus.includes(s) ? 'bg-eco-600 text-white shadow-md' : 'bg-gray-100 text-gray-500'}`}
                  >
                      {s === OrderStatus.PENDING ? 'Chờ' : s === OrderStatus.IN_TRANSIT ? 'Giao' : 'Xong'}
                  </button>
              ))}
              <button onClick={() => setShowRoutePlanner(true)} className="ml-auto px-4 py-1.5 bg-black text-white rounded-lg text-[10px] font-black uppercase shrink-0"><i className="fas fa-route mr-1"></i> Lộ trình</button>
          </div>
      </div>

      <div className={`mt-4 ${isCompactMode ? 'bg-white rounded-2xl overflow-hidden shadow-sm divide-y' : 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4'}`}>
          {filteredOrders.length === 0 ? (
              <div className="col-span-full py-20 text-center text-gray-300">
                  <i className="fas fa-box-open text-6xl mb-4 opacity-20"></i>
                  <p className="font-bold uppercase tracking-widest text-xs">Không có đơn hàng nào</p>
              </div>
          ) : (
              filteredOrders.map((o, idx) => (
                  <OrderCard 
                    key={o.id} 
                    order={o} 
                    index={idx}
                    isCompactMode={isCompactMode}
                    onDelete={handleDelete}
                    onEdit={() => {}}
                    onUpdate={() => {}}
                  />
              ))
          )}
      </div>

      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa đơn hàng?" message="Hành động này sẽ hoàn lại hàng vào kho và không thể khôi phục." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} isDanger={true} />
      <RoutePlannerModal isOpen={showRoutePlanner} onClose={() => setShowRoutePlanner(false)} orders={filteredOrders.filter(o => o.status !== OrderStatus.DELIVERED)} onApplySort={() => {}} />
    </div>
  );
};

export default TrackingDashboard;

import React from 'react';
import { Order, OrderStatus, PaymentMethod } from '../types';
import { storageService } from '../services/storageService';
import toast from 'react-hot-toast';

interface Props {
  order: Order;
  onUpdate: (order: Order) => void;
  onDelete: (id: string) => void;
  onEdit: (order: Order) => void;
  index?: number;
  isCompactMode?: boolean;
}

const statusStyle: Record<OrderStatus, string> = {
  [OrderStatus.PENDING]: 'bg-yellow-100 text-yellow-700',
  [OrderStatus.PICKED_UP]: 'bg-blue-100 text-blue-700',
  [OrderStatus.IN_TRANSIT]: 'bg-purple-100 text-purple-700',
  [OrderStatus.DELIVERED]: 'bg-green-100 text-green-700',
  [OrderStatus.CANCELLED]: 'bg-red-100 text-red-700',
};

const statusLabel: Record<OrderStatus, string> = {
  [OrderStatus.PENDING]: 'Chờ xử lý',
  [OrderStatus.PICKED_UP]: 'Đã lấy',
  [OrderStatus.IN_TRANSIT]: 'Đang giao',
  [OrderStatus.DELIVERED]: 'Đã giao',
  [OrderStatus.CANCELLED]: 'Đã hủy',
};

export const OrderCard: React.FC<Props> = ({ order, onDelete, isCompactMode, index }) => {

  const handleStatusNext = async (e: React.MouseEvent) => {
      e.stopPropagation();
      let next: OrderStatus = order.status;
      if (order.status === OrderStatus.PENDING) next = OrderStatus.PICKED_UP;
      else if (order.status === OrderStatus.PICKED_UP) next = OrderStatus.IN_TRANSIT;
      else if (order.status === OrderStatus.IN_TRANSIT) next = OrderStatus.DELIVERED;

      await storageService.updateStatus(order.id, next);
      toast.success(`Đã chuyển sang: ${statusLabel[next]}`);
  };

  const handleTogglePayment = async (e: React.MouseEvent) => {
      e.stopPropagation();
      if (order.paymentMethod !== PaymentMethod.TRANSFER) return;
      await storageService.updatePaymentVerification(order.id, !order.paymentVerified);
      toast.success(order.paymentVerified ? "Đã gỡ xác nhận" : "Đã khớp tiền!");
  };

  if (isCompactMode) {
      return (
          <div className="p-3 flex items-center gap-3 bg-white hover:bg-gray-50 transition-colors border-b border-gray-50">
              <div className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center text-[10px] font-black text-gray-400 shrink-0">{(index || 0) + 1}</div>
              <div className="flex-grow min-w-0">
                  <div className="flex justify-between items-baseline mb-0.5">
                      <h4 className="font-black text-gray-800 text-sm truncate uppercase">{order.customerName}</h4>
                      <span className="font-black text-gray-900 text-sm">{new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ</span>
                  </div>
                  <div className="flex items-center gap-2">
                      <span className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase ${statusStyle[order.status]}`}>{statusLabel[order.status]}</span>
                      <p className="text-[10px] text-gray-400 truncate">{order.address}</p>
                  </div>
              </div>
              <button onClick={handleStatusNext} className="w-9 h-9 rounded-xl bg-gray-900 text-white flex items-center justify-center shrink-0 shadow-md active:scale-90 transition-all"><i className="fas fa-chevron-right text-xs"></i></button>
          </div>
      );
  }

  return (
    <div className="bg-white rounded-3xl border-2 border-gray-100 shadow-sm overflow-hidden hover:shadow-xl hover:border-gray-200 transition-all flex flex-col h-full group">
        <div className="p-4 flex-grow">
            <div className="flex justify-between items-start mb-3">
                <div className="min-w-0">
                    <h3 className="font-black text-gray-800 uppercase text-base truncate tracking-tighter leading-none mb-1">{order.customerName}</h3>
                    <div className="flex items-center gap-2">
                        <span className="text-[10px] font-mono font-bold text-gray-400">{order.customerPhone}</span>
                        <span className={`text-[9px] font-black px-2 py-0.5 rounded-full uppercase ${statusStyle[order.status]}`}>{statusLabel[order.status]}</span>
                    </div>
                </div>
                <button onClick={(e) => { e.stopPropagation(); onDelete(order.id); }} className="w-8 h-8 rounded-full bg-red-50 text-red-300 hover:text-red-500 flex items-center justify-center transition-colors opacity-0 group-hover:opacity-100"><i className="fas fa-trash-alt text-xs"></i></button>
            </div>

            <div className="bg-gray-50 rounded-2xl p-3 border border-gray-100 mb-3 space-y-1">
                {order.items.map((it, i) => (
                    <div key={i} className="flex justify-between text-xs font-bold text-gray-700">
                        <span className="truncate mr-2 uppercase">{it.name}</span>
                        <span className="text-gray-400 shrink-0">x{it.quantity}</span>
                    </div>
                ))}
            </div>

            <div className="flex items-start gap-2 text-[10px] text-gray-500 font-medium">
                <i className="fas fa-map-marker-alt text-red-400 mt-0.5"></i>
                <span className="line-clamp-2">{order.address}</span>
            </div>
        </div>

        <div className="px-4 py-3 bg-gray-50 border-t border-gray-100 mt-auto flex justify-between items-center">
            <div>
                <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Tổng thu</div>
                <div className="text-lg font-black text-gray-900 tracking-tighter">{new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ</div>
            </div>

            <div className="flex gap-2">
                {order.paymentMethod === PaymentMethod.TRANSFER && (
                    <button onClick={handleTogglePayment} className={`px-3 py-2 rounded-xl text-[10px] font-black uppercase border-2 transition-all ${order.paymentVerified ? 'bg-green-50 border-green-500 text-green-700' : 'bg-blue-50 border-blue-200 text-blue-600'}`}>
                        {order.paymentVerified ? 'Đã nhận' : 'Chờ CK'}
                    </button>
                )}
                <button onClick={handleStatusNext} className="h-10 px-4 bg-black text-white rounded-xl font-black text-[10px] uppercase shadow-lg shadow-gray-200 active:scale-95 transition-all">
                    {order.status === OrderStatus.DELIVERED ? 'Xong ✅' : 'Tiếp theo'}
                </button>
            </div>
        </div>
    </div>
  );
};

import { Order, OrderStatus, Product, Customer, BankConfig, Notification, ShopConfig, ImportRecord, OrderItem, PaymentMethod } from '../types';
import { db } from '../firebaseConfig';
import { v4 as uuidv4 } from 'uuid';
import { 
  collection, 
  setDoc, 
  doc, 
  updateDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs, 
  writeBatch, 
  deleteField, 
  limit, 
  getDoc, 
  where, 
  increment,
  runTransaction 
} from "firebase/firestore";

const ORDER_KEY = 'ecogo_orders_v3'; 
const PRODUCT_KEY = 'ecogo_products_v1';
const CUSTOMER_KEY = 'ecogo_customers_v1';
const USER_KEY = 'ecogo_current_user';
const BANK_KEY = 'ecogo_bank_config';
const SHOP_KEY = 'ecogo_shop_config';
const NOTIF_KEY = 'ecogo_notifications_v1';
const TAGS_KEY = 'ecogo_quick_tags';
const LOGO_KEY = 'ecogo_company_logo';

const isOnline = () => !!db;

const getLocal = <T>(key: string, fallback: T): T => {
    try {
        const val = localStorage.getItem(key);
        return val ? JSON.parse(val) : fallback;
    } catch { return fallback; }
};

const setLocal = (key: string, val: any) => {
    localStorage.setItem(key, JSON.stringify(val));
    window.dispatchEvent(new Event('storage_' + key));
};

export const normalizeString = (str: string): string => {
    if (!str) return "";
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
};

export const normalizePhone = (phone: string) => {
    if (!phone) return '';
    let p = phone.replace(/[^0-9]/g, '');
    if (p.startsWith('84')) p = '0' + p.slice(2);
    if (p.startsWith('+84')) p = '0' + p.slice(3);
    return p;
};

export const generateProductSku = (name: string): string => {
    if (!name) return uuidv4();
    return name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "_");
};

const sanitize = (obj: any) => JSON.parse(JSON.stringify(obj));

export const storageService = {
  login: (username: string) => localStorage.setItem(USER_KEY, username),
  logout: () => localStorage.removeItem(USER_KEY),
  getCurrentUser: () => localStorage.getItem(USER_KEY),

  getLogo: () => localStorage.getItem(LOGO_KEY),
  saveLogo: (base64: string) => { localStorage.setItem(LOGO_KEY, base64); window.dispatchEvent(new Event('logo_updated')); },
  removeLogo: () => { localStorage.removeItem(LOGO_KEY); window.dispatchEvent(new Event('logo_updated')); },

  getQuickTags: () => getLocal(TAGS_KEY, ["Dễ vỡ", "Gọi trước", "Cổng sau"]),
  saveQuickTags: async (tags: string[]) => { setLocal(TAGS_KEY, tags); if (isOnline()) await setDoc(doc(db, "settings", "quickTags"), { tags }); },
  fetchQuickTagsFromCloud: async () => { if (isOnline()) { const s = await getDoc(doc(db, "settings", "quickTags")); if (s.exists()) return s.data().tags; } return storageService.getQuickTags(); },

  saveShopConfig: async (config: ShopConfig) => { setLocal(SHOP_KEY, config); if (isOnline()) await setDoc(doc(db, "settings", "shopConfig"), sanitize(config)); },
  getShopConfig: async () => getLocal(SHOP_KEY, null),

  saveBankConfig: async (config: BankConfig) => { setLocal(BANK_KEY, config); if (isOnline()) await setDoc(doc(db, "settings", "bankConfig"), sanitize(config)); },
  getBankConfig: async () => getLocal(BANK_KEY, null),

  getAllProducts: () => getLocal<Product[]>(PRODUCT_KEY, []),
  subscribeProducts: (callback: (prods: Product[]) => void) => {
    callback(storageService.getAllProducts());
    if (isOnline()) return onSnapshot(query(collection(db, "products"), orderBy("updatedAt", "desc"), limit(500)), (snap) => {
        const list = snap.docs.map(d => d.data() as Product);
        if (list.length > 0) { setLocal(PRODUCT_KEY, list); callback(list); }
    });
  },

  saveProduct: async (p: Product) => {
      const list = storageService.getAllProducts();
      const idx = list.findIndex(x => x.id === p.id);
      const pSave = { ...p, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = pSave; else list.unshift(pSave);
      setLocal(PRODUCT_KEY, list);
      if (isOnline()) await setDoc(doc(db, "products", p.id), sanitize(pSave));
  },

  adjustStockAtomic: async (id: string, delta: number, info?: any) => {
      const list = storageService.getAllProducts();
      const p = list.find(x => x.id === id);
      if (p) {
          p.stockQuantity = (p.stockQuantity || 0) + delta;
          if (delta > 0) {
              p.totalImported = (p.totalImported || 0) + delta;
              if (!p.importHistory) p.importHistory = [];
              p.importHistory.push({ id: uuidv4(), date: Date.now(), quantity: delta, price: info?.price || 0 });
          }
          p.updatedAt = Date.now();
          setLocal(PRODUCT_KEY, list);
      }
      if (isOnline()) await runTransaction(db, async (tx) => {
          const ref = doc(db, "products", id);
          const snap = await tx.get(ref);
          if (snap.exists()) {
              const data = snap.data() as Product;
              const updates: any = { stockQuantity: increment(delta), updatedAt: Date.now() };
              if (delta > 0) {
                  updates.totalImported = increment(delta);
                  const h = [...(data.importHistory || []), { id: uuidv4(), date: Date.now(), quantity: delta, price: info?.price || 0 }];
                  updates.importHistory = h;
              }
              tx.update(ref, updates);
          }
      });
  },

  // --- RESTORED: SYNC PRODUCT DATA TO PENDING ORDERS ---
  syncProductToPendingOrders: async (product: Product) => {
      const orders = getLocal<Order[]>(ORDER_KEY, []);
      let hasChanges = false;
      const batch = isOnline() ? writeBatch(db) : null;

      orders.forEach(order => {
          if (order.status !== OrderStatus.DELIVERED && order.status !== OrderStatus.CANCELLED) {
              let orderUpdated = false;
              order.items.forEach(item => {
                  if (item.productId === product.id) {
                      // Update name and import price (cost) for correct profit calculation later
                      if (item.name !== product.name || item.importPrice !== product.importPrice) {
                          item.name = product.name;
                          item.importPrice = product.importPrice;
                          // Optional: update item.price if you want selling price to update too, 
                          // but usually we keep selling price fixed after order creation unless manually changed.
                          orderUpdated = true;
                      }
                  }
              });

              if (orderUpdated) {
                  order.updatedAt = Date.now();
                  hasChanges = true;
                  if (batch) batch.set(doc(db, "orders", order.id), sanitize(order));
              }
          }
      });

      if (hasChanges) {
          setLocal(ORDER_KEY, orders);
          if (batch) await batch.commit();
      }
  },

  // --- RESTORED: RECALCULATE INVENTORY ---
  recalculateInventoryFromOrders: async () => {
      const products = getLocal<Product[]>(PRODUCT_KEY, []);
      const orders = getLocal<Order[]>(ORDER_KEY, []);

      const batch = isOnline() ? writeBatch(db) : null;
      let hasChanges = false;

      products.forEach(p => {
          // 1. Calculate Total Imported from history
          let totalImported = 0;
          if (p.importHistory && p.importHistory.length > 0) {
              totalImported = p.importHistory.reduce((sum, h) => sum + h.quantity, 0);
          } else {
              // Fallback for legacy data
              totalImported = p.totalImported || p.stockQuantity;
          }

          // 2. Calculate Total Sold from Active orders
          let totalSold = 0;
          orders.forEach(o => {
              if (o.status !== OrderStatus.CANCELLED) {
                  o.items.forEach(i => {
                      if (i.productId === p.id) {
                          totalSold += Number(i.quantity) || 0;
                      }
                  });
              }
          });

          // 3. Update correct stock
          const newStock = totalImported - totalSold;

          if (p.stockQuantity !== newStock || p.totalImported !== totalImported) {
              p.stockQuantity = newStock;
              p.totalImported = totalImported;
              p.updatedAt = Date.now();
              hasChanges = true;
              if (batch) batch.update(doc(db, "products", p.id), { 
                  stockQuantity: newStock, 
                  totalImported: totalImported,
                  updatedAt: Date.now() 
              });
          }
      });

      if (hasChanges) {
          setLocal(PRODUCT_KEY, products);
          if (batch) await batch.commit();
          return true;
      }
      return false;
  },

  deleteProduct: async (id: string) => {
      const list = storageService.getAllProducts().filter(x => x.id !== id);
      setLocal(PRODUCT_KEY, list);
      if (isOnline()) await deleteDoc(doc(db, "products", id));
  },

  subscribeOrders: (callback: (orders: Order[]) => void) => {
    callback(getLocal<Order[]>(ORDER_KEY, []));
    if (isOnline()) return onSnapshot(query(collection(db, "orders"), orderBy("createdAt", "desc"), limit(400)), (snap) => {
        const list = snap.docs.map(d => d.data() as Order);
        setLocal(ORDER_KEY, list);
        callback(list);
    });
  },

  saveOrder: async (o: Order) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      list.unshift(o);
      setLocal(ORDER_KEY, list);

      const prods = storageService.getAllProducts();
      o.items.forEach(item => {
          const p = prods.find(x => x.id === item.productId);
          if (p) p.stockQuantity -= item.quantity;
      });
      setLocal(PRODUCT_KEY, prods);

      if (isOnline()) await runTransaction(db, async (tx) => {
          for (const item of o.items) {
              if (item.productId) tx.update(doc(db, "products", item.productId), { stockQuantity: increment(-item.quantity), updatedAt: Date.now() });
          }
          tx.set(doc(db, "orders", o.id), sanitize(o));
      });
  },

  saveOrdersList: async (orders: Order[]) => {
      setLocal(ORDER_KEY, orders);
      if (!isOnline()) return;
      const batch = writeBatch(db);
      orders.forEach(o => {
          batch.set(doc(db, "orders", o.id), sanitize(o));
      });
      await batch.commit();
  },

  deleteOrder: async (id: string, customerInfo?: {name: string, address: string}) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const o = list.find(x => x.id === id);
      if (!o) return;

      setLocal(ORDER_KEY, list.filter(x => x.id !== id));
      const prods = storageService.getAllProducts();
      o.items.forEach(item => {
          const p = prods.find(x => x.id === item.productId);
          if (p) p.stockQuantity += item.quantity;
      });
      setLocal(PRODUCT_KEY, prods);

      if (isOnline()) await runTransaction(db, async (tx) => {
          const ref = doc(db, "orders", id);
          const snap = await tx.get(ref);
          if (snap.exists()) {
              const data = snap.data() as Order;
              for (const it of data.items) {
                  if (it.productId) tx.update(doc(db, "products", it.productId), { stockQuantity: increment(it.quantity), updatedAt: Date.now() });
              }
              tx.delete(ref);
          }
      });
  },

  deleteOrdersBatch: async (ids: string[]) => { for (const id of ids) await storageService.deleteOrder(id); },

  updateStatus: async (id: string, status: OrderStatus, proof?: string, meta?: any) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const idx = list.findIndex(x => x.id === id);
      if (idx >= 0) {
          list[idx].status = status;
          list[idx].updatedAt = Date.now();
          if (proof) list[idx].deliveryProof = proof;
          setLocal(ORDER_KEY, list);
          if (isOnline()) await updateDoc(doc(db, "orders", id), { status, updatedAt: Date.now(), deliveryProof: proof || deleteField() });
      }
  },

  updateOrderDetails: async (o: Order) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const idx = list.findIndex(x => x.id === o.id);
      if (idx >= 0) {
          list[idx] = { ...o, updatedAt: Date.now() };
          setLocal(ORDER_KEY, list);
          if (isOnline()) await setDoc(doc(db, "orders", o.id), sanitize(list[idx]));
      }
  },

  updatePaymentVerification: async (id: string, verified: boolean, meta?: any) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const idx = list.findIndex(x => x.id === id);
      if (idx >= 0) {
          list[idx].paymentVerified = verified;
          list[idx].updatedAt = Date.now();
          setLocal(ORDER_KEY, list);
          if (isOnline()) await updateDoc(doc(db, "orders", id), { paymentVerified: verified, updatedAt: Date.now() });
      }
  },

  moveOrdersBatch: async (ids: string[], target: string) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const batch = isOnline() ? writeBatch(db) : null;
      ids.forEach(id => {
          const o = list.find(x => x.id === id);
          if (o) {
              o.batchId = target;
              o.updatedAt = Date.now();
              if (batch) batch.update(doc(db, "orders", id), { batchId: target, updatedAt: o.updatedAt });
          }
      });
      setLocal(ORDER_KEY, list);
      if (batch) await batch.commit();
  },

  renameBatch: async (oldName: string, newName: string) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const batch = isOnline() ? writeBatch(db) : null;
      list.forEach(o => {
          if (o.batchId === oldName) {
              o.batchId = newName;
              o.updatedAt = Date.now();
              if (batch) batch.update(doc(db, "orders", o.id), { batchId: newName, updatedAt: o.updatedAt });
          }
      });
      setLocal(ORDER_KEY, list);
      if (batch) await batch.commit();
  },

  splitOrderToNextBatch: async (id: string, currentBatch: string) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const idx = list.findIndex(x => x.id === id);
      if (idx >= 0) {
          // Generate next batch name roughly: current + "-SAU" or increment
          const nextBatch = currentBatch.includes('-SAU') ? currentBatch : `${currentBatch}-SAU`;
          list[idx].batchId = nextBatch;
          list[idx].updatedAt = Date.now();
          setLocal(ORDER_KEY, list);
          if (isOnline()) await updateDoc(doc(db, "orders", id), { batchId: nextBatch, updatedAt: Date.now() });
      }
  },

  splitOrdersBatch: async (orders: {id: string, batchId: string}[]) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      const batch = isOnline() ? writeBatch(db) : null;
      orders.forEach(({id, batchId}) => {
          const o = list.find(x => x.id === id);
          if(o) {
              const nextBatch = batchId.includes('-SAU') ? batchId : `${batchId}-SAU`;
              o.batchId = nextBatch;
              o.updatedAt = Date.now();
              if(batch) batch.update(doc(db, "orders", id), { batchId: nextBatch, updatedAt: o.updatedAt });
          }
      });
      setLocal(ORDER_KEY, list);
      if(batch) await batch.commit();
  },

  learnRoutePriority: async (orders: Order[]) => {
      // Placeholder for AI learning logic (can be expanded)
      // Currently just saves the re-ordered indexes which is sufficient for simple usage
  },

  subscribeCustomers: (callback: (c: Customer[]) => void) => {
      callback(getLocal<Customer[]>(CUSTOMER_KEY, []));
      if (isOnline()) return onSnapshot(query(collection(db, "customers"), orderBy("updatedAt", "desc"), limit(1000)), (snap) => {
          const list = snap.docs.map(d => d.data() as Customer);
          setLocal(CUSTOMER_KEY, list);
          callback(list);
      });
  },

  upsertCustomer: async (c: Customer) => {
      const list = getLocal<Customer[]>(CUSTOMER_KEY, []);
      const idx = list.findIndex(x => x.id === c.id);
      const cSave = { ...c, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = cSave; else list.unshift(cSave);
      setLocal(CUSTOMER_KEY, list);
      if (isOnline()) await setDoc(doc(db, "customers", c.id), sanitize(cSave));
  },

  deleteCustomer: async (id: string) => {
      setLocal(CUSTOMER_KEY, getLocal<Customer[]>(CUSTOMER_KEY, []).filter(x => x.id !== id));
      if (isOnline()) await deleteDoc(doc(db, "customers", id));
  },

  subscribeNotifications: (callback: (n: Notification[]) => void) => {
      callback(getLocal<Notification[]>(NOTIF_KEY, []));
      if (isOnline()) return onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc"), limit(50)), (snap) => {
          const list = snap.docs.map(d => d.data() as Notification);
          setLocal(NOTIF_KEY, list);
          callback(list);
      });
  },

  markNotificationRead: async (id: string) => {
      if (isOnline()) await updateDoc(doc(db, "notifications", id), { isRead: true });
  },

  markAllNotificationsRead: async () => {
      const list = getLocal<Notification[]>(NOTIF_KEY, []);
      list.forEach(n => n.isRead = true);
      setLocal(NOTIF_KEY, list);
  },

  clearAllNotifications: async () => localStorage.removeItem(NOTIF_KEY),

  findMatchingCustomer: (phone: string, address: string, id?: string) => {
      const list = getLocal<Customer[]>(CUSTOMER_KEY, []);
      if (id) {
          const byId = list.find(c => c.id === id);
          if (byId) return byId;
      }
      const p = normalizePhone(phone);
      if (p.length > 8) return list.find(c => normalizePhone(c.phone) === p);
      return list.find(c => normalizeString(c.address) === normalizeString(address));
  },

  getProductOrderHistory: (id: string) => {
      const orders = getLocal<Order[]>(ORDER_KEY, []);
      const history: any[] = [];
      orders.forEach(o => {
          o.items.forEach(it => { if (it.productId === id) history.push({ order: o, quantity: it.quantity }); });
      });
      return history;
  },

  fetchLongTermStats: async () => {
      if (isOnline()) { const s = await getDocs(query(collection(db, "orders"), limit(2000))); return s.docs.map(d => d.data() as Order); }
      return getLocal<Order[]>(ORDER_KEY, []);
  },

  incrementReminderCount: async (ids: string[]) => {
      const list = getLocal<Order[]>(ORDER_KEY, []);
      ids.forEach(id => { const o = list.find(x => x.id === id); if (o) o.reminderCount = (o.reminderCount || 0) + 1; });
      setLocal(ORDER_KEY, list);
  },

  generatePerformanceData: async (count: number) => ({ count, duration: 0 }),
  markAllCustomersAsOld: async () => 0
};

